previewCss:
.darma-loader-darma-custom-595 {color: var(--loader-color, #dc2626);
  --loader-secondary-color: #f97316;
  --loader-bg: #ffffff;
   width: 100px;
   height: 30px;
   display: flex;
   justify-content: center;
}
.darma-loader-darma-custom-595:before, .darma-loader-darma-custom-595:after  {
  content: "";
   background: currentColor;
   width: 15px;
   clip-path: polygon(0 10px,calc(100% - 15px) 10px,calc(100% - 15px) 0,100% 50%,calc(100% - 15px) 100%,calc(100% - 15px) calc(100% - 10px),0 calc(100% - 10px));
   animation: darma-loader-darma-custom-595-l2 1s infinite linear;
}
.darma-loader-darma-custom-595:before  {
  transform: scaleX(-1);
}
@keyframes darma-loader-darma-custom-595-l2  {
  90%,100%{flex-grow: .5}
}

